import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useAppContext } from '../../context/AppContext';

const Navbar = () => {
  const { darkMode, toggleDarkMode } = useAppContext();
  const location = useLocation();

  const isActive = (path) => location.pathname === path;

  return (
    <nav className="bg-white dark:bg-gray-800 shadow p-4 flex flex-col md:flex-row md:justify-between md:items-center gap-4">
      <div className="flex items-center gap-6">
        <Link to="/dashboard" className="text-xl font-bold text-blue-600 dark:text-blue-400">
          OzonInsight
        </Link>
        <div className="flex gap-4">
          <Link
            to="/dashboard"
            className={`text-sm ${isActive('/dashboard') ? 'font-bold text-blue-600 dark:text-blue-400' : 'text-gray-600 dark:text-gray-300'}`}
          >
            Общий
          </Link>
          <Link
            to="/returns"
            className={`text-sm ${isActive('/returns') ? 'font-bold text-blue-600 dark:text-blue-400' : 'text-gray-600 dark:text-gray-300'}`}
          >
            Возвраты
          </Link>
          <Link
            to="/stock"
            className={`text-sm ${isActive('/stock') ? 'font-bold text-blue-600 dark:text-blue-400' : 'text-gray-600 dark:text-gray-300'}`}
          >
            Остатки
          </Link>
          <Link
            to="/logistics"
            className={`text-sm ${isActive('/logistics') ? 'font-bold text-blue-600 dark:text-blue-400' : 'text-gray-600 dark:text-gray-300'}`}
          >
            Логистика
          </Link>
        </div>
      </div>
      <div className="flex items-center gap-4">
        <button onClick={toggleDarkMode} className="text-sm px-3 py-1 rounded bg-gray-200 dark:bg-gray-700">
          {darkMode ? 'Светлая тема' : 'Тёмная тема'}
        </button>
      </div>
    </nav>
  );
};

export default Navbar;
